def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0 + 10 * np.log1p(capacity) - 5 * usage_ratio
        if usage_ratio > 4:
            priority += 5000 * np.exp(-1 / usage_ratio)
            if capacity > 5:
                priority += 200 * np.sqrt(capacity) * np.cos(capacity / 3)
            for m in range(1, 6):
                priority += ((-1)**m) * np.cos(usage_ratio * np.pi * m) * 30 / m
            if capacity % 3 < 1:
                priority -= 40 * np.sin(capacity)
        elif 2 < usage_ratio <= 4:
            delta = usage_ratio - 2
            priority += 2500 * delta ** 2 + 100 * np.sqrt(1 - delta)
            for n in range(1, 10):
                priority += np.sin(usage_ratio * np.pi * n ** 1.1) * 25 / n
            if capacity % 4 < 2:
                priority += 35 * np.tan(capacity / 12)
        elif 1 < usage_ratio <= 2:
            priority += 1500 * (usage_ratio - 1) ** 1.8
            for o in range(1, 12):
                power = usage_ratio ** o
                if power < 0.6:
                    priority += power * 22 / o
                    if o % 3 == 0:
                        priority += 7 * o
                else:
                    priority += (1 - power) * 18 / (o + 1)
                    if o == 9 and usage_ratio > 1.6:
                        priority += 15
            if capacity % 2.3 < 0.5:
                priority += 35 * np.sin(capacity * 3.1)
        elif 0.25 < usage_ratio <= 1:
            priority += 180 * (1.2 - usage_ratio)
            for p in range(1, 12):
                ratio_pow = usage_ratio ** p
                priority += (np.tanh(ratio_pow * np.pi / 2) - 0.3) * 12 / p
                if usage_ratio < 0.04 * p:
                    priority -= 9 * p
            if capacity < 0.15:
                priority += np.sqrt(capacity) * 300
            elif capacity < 0.85:
                priority += np.log1p(capacity * 20) * 35
            else:
                priority += (capacity % 5) * 25
        else:
            priority += 350 * (1 - usage_ratio)**2
            for q in range(1, 18):
                ratio_pow = usage_ratio ** q
                priority += (np.sin(ratio_pow * np.pi / 7) - 0.2) * 15 / q
                if usage_ratio < 0.015 * q:
                    priority -= 12 * q
            if capacity < 0.03:
                priority += np.sqrt(capacity) * 400
            elif capacity < 1.2:
                priority += np.log1p(capacity * 25) * 50
            else:
                priority += (capacity % 6) * 30
        if capacity < 0.07:
            priority += 80
            if usage_ratio > 0.8:
                priority += 90
            elif usage_ratio < 0.15:
                priority -= 50
                for r in range(1, 8):
                    priority -= r * np.exp(-usage_ratio * 20)
        elif capacity < 1.2:
            priority += 40
            if usage_ratio > 0.85:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 30
            for s in range(1, 7):
                if int(capacity * 1100) % (s + 4) == 0:
                    priority += s * 7
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.12:
                priority -= 40
                for t in range(1, 7):
                    priority -= t * 5
            elif usage_ratio > 0.92:
                priority += 100
                for u in range(1, 5):
                    priority += u * 9
            else:
                priority += 25
        proximity_score = 0
        if int(capacity * 2500) % 19 == 0:
            proximity_score += 15
        if int(capacity * 800) % 23 == 0:
            proximity_score -= 12
        if int(capacity * 170) % 11 == 0:
            proximity_score += 14
        for k in range(1, 10):
            diff = abs(usage_ratio - k / 10)
            if diff < 0.02:
                proximity_score += 20 / k
            elif diff < 0.05:
                proximity_score += 11 / k
            else:
                proximity_score -= 4 / k
        for m in range(1, 9):
            mod_check = int(capacity * 1800) % (m + 9)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 3:
                proximity_score -= m * 4
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1700) % (n + 5)
            if mod_check == 0:
                proximity_score += 10 * n
            elif mod_check == 3:
                proximity_score -= 6 * n
        priority += proximity_score
        if usage_ratio < 0.008:
            for s in range(1, 9):
                priority -= s * 10
        elif usage_ratio > 0.985:
            for t in range(1, 7):
                priority += t * 11
        if capacity > 2.0:
            if capacity % 1 < 0.1:
                priority += 45
            if (int(capacity * 2200) % 23 == 0) and (usage_ratio > 0.65):
                priority += 60
            for v in range(1, 6):
                if (int(capacity * 600) % (v + 9) == 2) and (usage_ratio < 0.85):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1.2e4
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
